"use client";

import { Check, ExternalLink, RotateCcw } from "lucide-react";
import { useStackshift } from "@/store";

const btnBase    = "inline-flex items-center gap-2 px-[22px] py-[13px] font-sans font-medium text-sm border cursor-pointer transition-all duration-[120ms] rounded-[3px] hover:-translate-x-0.5 hover:-translate-y-0.5";
const btnDefault = `${btnBase} bg-ink text-paper border-line hover:shadow-btn-accent`;
const btnPrimary = `${btnBase} bg-accent text-paper border-accent hover:shadow-btn-ink hover:bg-accent-2`;

export default function DoneStep() {
  const result  = useStackshift((s) => s.migrationResult);
  const reset   = useStackshift((s) => s.reset);
  const setStep = useStackshift((s) => s.setStep);

  if (!result) {
    return (
      <>
        <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
          <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">06 / DONE</span>
          <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
            No migration <em className="italic font-normal text-accent">yet</em>.
          </h2>
        </div>
        <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
          Head back to the preview step and push a migration first.
        </p>
        <button className={btnDefault} onClick={() => setStep("preview")}>← Back to preview</button>
      </>
    );
  }

  const seconds = (result.elapsedMs / 1000).toFixed(1);
  const label   = result.dryRun ? "DRY-RUN" : result.success ? "DONE" : "FAILED";

  return (
    <>
      <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
        <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">06 / {label}</span>
        <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
          {result.dryRun
            ? <>Dry-run <em className="italic font-normal text-accent">complete</em>.</>
            : result.success
              ? <>Landed in <em className="italic font-normal text-accent">Contentstack</em>.</>
              : <>Migration <em className="italic font-normal text-accent">failed</em>.</>}
        </h2>
      </div>

      {result.dryRun && result.payload ? (
        <>
          <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
            Nothing was written. Below is the exact JSON we would have sent.
          </p>
          <div className="bg-card border border-line shadow-hard rounded-[3px] overflow-hidden transition-all duration-[180ms] hover:-translate-x-px hover:-translate-y-px hover:shadow-hard-hover">
            <div className="flex items-center gap-2.5 px-4 py-[11px] bg-paper-2 border-b border-line font-mono text-[11px] text-muted">
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#ff5f57]" />
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#febc2e]" />
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#28c840]" />
              <span className="flex-1 bg-card border border-line px-2.5 py-[5px] rounded-[2px] ml-3">payload.json</span>
            </div>
            <pre className="m-0 p-6 bg-ink text-[#a8e6a3] font-mono text-xs leading-[1.7] max-h-[480px] overflow-auto">
              {JSON.stringify(result.payload, null, 2)}
            </pre>
          </div>
        </>
      ) : (
        <div className="text-center py-10 px-5">
          <div className="w-[90px] h-[90px] border-2 border-brand-green rounded-full flex items-center justify-center mx-auto mb-6 text-brand-green text-[42px] font-medium bg-green-soft">
            <Check size={42} />
          </div>
          <h3 className="font-serif font-medium text-[36px] tracking-[-1px] mb-2.5">
            {result.success ? "Done in" : "Partial run —"} {seconds}s
          </h3>
          <p className="text-muted text-[15px] max-w-[400px] mx-auto mb-8 leading-[1.5]">
            {result.success
              ? "Your content types and entries are live. Open Contentstack to see them."
              : "Some operations failed. Check the log below for details."}
          </p>

          <div className="grid max-w-[700px] mx-auto border border-line bg-card rounded-[3px] overflow-hidden" style={{ gridTemplateColumns: "repeat(3, 1fr)" }}>
            {[
              { num: result.entriesCreated,      lbl: "Entries created" },
              { num: result.contentTypesCreated,  lbl: "Types created" },
              { num: `${seconds}s`,               lbl: "Elapsed" },
            ].map(({ num, lbl }, i) => (
              <div key={lbl} className={`p-6 text-left ${i < 2 ? "border-r border-line/20" : ""}`}>
                <div className="font-serif text-[42px] font-medium tracking-[-1px] leading-none text-accent">{num}</div>
                <div className="font-mono text-[10px] uppercase tracking-[1.5px] text-muted mt-2">{lbl}</div>
              </div>
            ))}
          </div>

          {result.pageEntryUid && (
            <div className="mt-5 max-w-[700px] mx-auto px-5 py-3.5 bg-paper-2 border border-line rounded-[3px] font-mono text-[11px] text-muted flex items-center gap-2 flex-wrap">
              <span className="text-brand-green font-semibold">✓ Page entry created</span>
              <span className="text-ink">{result.pageEntryUid}</span>
            </div>
          )}
        </div>
      )}

      {result.logs.length > 0 && (
        <div className="text-left max-w-[700px] mx-auto mt-8 bg-ink text-[#a8e6a3] px-6 py-5 font-mono text-xs leading-[1.8] border border-line overflow-x-auto rounded-[3px]">
          {result.logs.map((l, i) => (
            <div key={i}>
              <span className="text-paper-2">[{new Date(l.timestamp).toLocaleTimeString()}]</span>{" "}
              <span className="text-accent-soft">{l.level.toUpperCase()}</span>{" "}
              {l.message}
            </div>
          ))}
        </div>
      )}

      <div className="mt-8 flex gap-3 justify-center flex-wrap">
        <button className={btnDefault} onClick={() => { reset(); setStep("url"); }}>
          <RotateCcw size={14} /> Migrate another page
        </button>
        {result.stackUrl && (
          <a className={btnPrimary} href={result.stackUrl} target="_blank" rel="noopener noreferrer">
            Open in Contentstack <ExternalLink size={14} />
          </a>
        )}
      </div>
    </>
  );
}
