"use client";

import { useMemo, useState } from "react";
import { Eye, ArrowRight } from "lucide-react";
import { useStackshift } from "@/store";
import type { MatchResponse } from "@/types";

const btnBase    = "inline-flex items-center gap-2 px-3.5 py-2 font-sans font-medium text-xs border cursor-pointer transition-all duration-[120ms] rounded-[3px] disabled:opacity-45 disabled:cursor-not-allowed disabled:pointer-events-none";
const btnDefault = `${btnBase} bg-transparent text-paper border-paper hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-accent`;
const btnPrimary = `${btnBase} bg-accent border-accent text-paper hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-accent-2`;
const btnGhost   = `${btnBase} bg-transparent text-ink border-line hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-card`;

export default function DetectStep() {
  const components     = useStackshift((s) => s.components);
  const selectedIds    = useStackshift((s) => s.selectedIds);
  const scannedUrl     = useStackshift((s) => s.url);
  const config         = useStackshift((s) => s.config);
  const toggle         = useStackshift((s) => s.toggleComponentSelected);
  const selectAll      = useStackshift((s) => s.selectAll);
  const selectNone     = useStackshift((s) => s.selectNone);
  const setStep        = useStackshift((s) => s.setStep);
  const setMatches     = useStackshift((s) => s.setMatches);

  const [inspecting, setInspecting] = useState<string | null>(null);
  const [busy, setBusy]             = useState(false);
  const [err, setErr]               = useState<string | null>(null);

  const selectedCount      = selectedIds.length;
  const totalCount         = components.length;
  const selectedComponents = useMemo(() => components.filter((c) => selectedIds.includes(c.id)), [components, selectedIds]);

  const handleContinue = async () => {
    setErr(null);
    if (!selectedCount) { setErr("Select at least one component."); return; }
    setBusy(true);
    try {
      const res  = await fetch("/api/contentstack/match", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ config, components: selectedComponents }) });
      const data = (await res.json()) as MatchResponse;
      if (!data.ok) { setErr(data.error ?? "Match failed."); return; }
      setMatches(data.matches);
      setStep("match");
    } catch (e) {
      setErr(e instanceof Error ? e.message : "Network error.");
    } finally { setBusy(false); }
  };

  return (
    <>
      <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
        <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">03 / DETECT</span>
        <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
          Components we <em className="italic font-normal text-accent">spotted</em>.
        </h2>
      </div>
      <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
        Pick which blocks you want in Contentstack. Each row shows confidence, a preview, and where it came from. Deselect anything noisy.
      </p>

      {/* toolbar */}
      <div className="flex justify-between items-center px-5 py-4 bg-ink text-paper border border-line border-b-0 rounded-tl-[3px] rounded-tr-[3px]">
        <div className="font-mono text-xs tracking-[1px]">
          <strong className="text-accent-soft text-sm mr-1.5">{selectedCount}</strong>/ {totalCount} selected
        </div>
        <div className="flex gap-3">
          <button className={btnDefault} onClick={selectAll}>Select all</button>
          <button className={btnDefault} onClick={selectNone}>Clear</button>
          <button className={btnPrimary} onClick={handleContinue} disabled={busy || !selectedCount}>
            {busy
              ? <><span className="inline-block w-3.5 h-3.5 rounded-full border-2 border-paper-2 border-t-accent animate-spin" /> Matching…</>
              : <>Continue to matching <ArrowRight size={12} /></>}
          </button>
        </div>
      </div>

      {/* rows */}
      <div className="border border-line rounded-bl-[3px] rounded-br-[3px] overflow-hidden">
        {components.map((c) => {
          const selected = selectedIds.includes(c.id);
          const pct      = Math.round(c.confidence * 100);
          const barColor = c.confidence >= 0.8 ? "bg-brand-green" : c.confidence >= 0.7 ? "bg-accent" : "bg-brand-yellow";
          return (
            <div
              key={c.id}
              className={`grid items-center gap-0 px-5 py-[18px] border-b border-line/20 last:border-b-0 transition-colors duration-150 ${selected ? "bg-accent-soft" : "bg-card hover:bg-paper"}`}
              style={{ gridTemplateColumns: "44px 1fr 180px 120px 100px" }}
            >
              <span
                className={`w-5 h-5 border-[1.5px] inline-flex items-center justify-center flex-shrink-0 rounded-[3px] transition-all duration-[120ms] cursor-pointer ${selected ? "bg-ink text-paper border-ink" : "bg-card border-line hover:border-accent"}`}
                onClick={() => toggle(c.id)}
              >
                {selected && <span className="text-[13px] font-bold leading-none">✓</span>}
              </span>

              <div className="font-medium text-base flex flex-col gap-1">
                <span>{c.name}</span>
                <span className="font-mono text-[10px] text-muted uppercase tracking-[1.5px]">{c.kind} · {c.selector}</span>
              </div>

              <div className="text-sm text-muted font-serif italic overflow-hidden text-ellipsis whitespace-nowrap pr-5">{c.preview}</div>

              <div className="flex items-center gap-2 font-mono text-[11px]">
                <div className="flex-1 h-1 bg-paper-2 relative overflow-hidden rounded-sm">
                  <div className={`conf-fill ${barColor}`} style={{ ["--w" as string]: `${pct}%` }} />
                </div>
                <span>{pct}%</span>
              </div>

              <button className={btnGhost} onClick={() => setInspecting(inspecting === c.id ? null : c.id)}>
                <Eye size={12} /> Inspect
              </button>
            </div>
          );
        })}
      </div>

      {/* inspect panel */}
      {inspecting && (() => {
        const ic     = components.find((c) => c.id === inspecting);
        const srcdoc = ic?.previewHtml
          ? `<!DOCTYPE html><html><head><base href="${scannedUrl}"><meta name="viewport" content="width=device-width,initial-scale=1"><style>*,*::before,*::after{box-sizing:border-box}body{margin:0;padding:0}img{max-width:100%}</style></head><body>${ic.previewHtml}</body></html>`
          : null;
        return (
          <div className="border border-line bg-paper p-7 shadow-hard mt-3.5 rounded-[3px]">
            <div className="flex justify-between items-baseline mb-5 pb-4 border-b border-dashed border-line">
              <h3 className="font-serif font-medium text-2xl tracking-[-0.5px]">Inspect — {ic?.name}</h3>
              <span className="font-mono text-[11px] text-accent uppercase tracking-[2px]">{ic?.selector}</span>
            </div>
            {srcdoc && (
              <div className="border border-line/20 rounded-[3px] overflow-hidden bg-card-hi mb-5">
                <iframe srcDoc={srcdoc} sandbox="allow-same-origin" title="Component preview" className="block w-full h-[340px] border-none" />
              </div>
            )}
            <pre className="font-mono text-xs leading-[1.7] text-muted whitespace-pre-wrap max-h-[300px] overflow-auto">
              {JSON.stringify(ic?.fields, null, 2)}
            </pre>
          </div>
        );
      })()}

      {err && <p className="mt-4 text-accent text-sm">{err}</p>}
    </>
  );
}
