"use client";

import { Settings, LogOut, CircleDot } from "lucide-react";
import { useStackshift } from "@/store";

export default function Masthead() {
  const connectionOk = useStackshift((s) => s.connectionOk);
  const contentTypeCount = useStackshift((s) => s.contentTypeCount);
  const region = useStackshift((s) => s.config.region);
  const stackName = useStackshift((s) => s.stackName);
  const connectedAt = useStackshift((s) => s.connectedAt);
  const setConfigPanelOpen = useStackshift((s) => s.setConfigPanelOpen);
  const disconnect = useStackshift((s) => s.disconnect);

  const shortStack = stackName
    ? stackName.length > 22 ? `${stackName.slice(0, 22)}…` : stackName
    : region.toUpperCase();

  return (
    <header className="sticky top-0 z-20 flex items-center justify-between gap-8 px-12 py-6 border-b border-line bg-gradient-to-b from-paper-3 to-paper backdrop-saturate-[1.2]">
      <div className="min-w-0">
        <h1 className="font-serif font-medium text-[44px] leading-[0.95] tracking-[-1.8px]">
          Stack<em className="italic font-normal text-accent">shift</em>
        </h1>
        <div className="mt-1.5 font-mono text-[10.5px] tracking-[1.8px] uppercase text-muted">
          A content migration tool for Contentstack · Casual Coders
        </div>
      </div>

      <div className="flex items-center gap-3">
        {connectionOk ? (
          <div className="inline-flex items-center gap-3 px-3.5 py-2.5 bg-card border border-line shadow-hard-sm rounded-[4px] transition-all duration-[120ms] hover:-translate-x-px hover:-translate-y-px hover:shadow-hard">
            <span className="inline-flex text-brand-green animate-conn-pulse" aria-hidden>
              <CircleDot size={10} />
            </span>
            <div className="flex flex-col leading-[1.25] min-w-0">
              <span className="font-mono text-[10px] tracking-[1.6px] uppercase text-muted">Connected</span>
              <span className="text-[12.5px] font-medium text-ink whitespace-nowrap max-w-[360px] overflow-hidden text-ellipsis">
                {shortStack} · {region.toUpperCase()} · {contentTypeCount ?? 0} CTs
                {connectedAt ? ` · ${timeAgo(connectedAt)}` : ""}
              </span>
            </div>
            <div className="inline-flex gap-1 ml-1 pl-2.5 border-l border-line/20">
              <button
                className="w-[30px] h-[30px] inline-flex items-center justify-center bg-transparent border border-transparent text-ink rounded-[3px] cursor-pointer transition-all duration-[120ms] hover:bg-paper-2 hover:border-line/20 hover:text-accent"
                title="Manage connection"
                aria-label="Manage connection"
                onClick={() => setConfigPanelOpen(true)}
              >
                <Settings size={14} />
              </button>
              <button
                className="w-[30px] h-[30px] inline-flex items-center justify-center bg-transparent border border-transparent text-ink rounded-[3px] cursor-pointer transition-all duration-[120ms] hover:bg-paper-2 hover:border-line/20 hover:text-accent"
                title="Sign out"
                aria-label="Sign out"
                onClick={() => { if (confirm("Disconnect and clear saved credentials?")) disconnect(); }}
              >
                <LogOut size={14} />
              </button>
            </div>
          </div>
        ) : (
          <div className="inline-flex items-center gap-3 px-3.5 py-2.5 bg-paper-2 border border-line shadow-hard-sm rounded-[4px]">
            <span className="inline-flex text-accent" aria-hidden>
              <CircleDot size={10} />
            </span>
            <div className="flex flex-col leading-[1.25]">
              <span className="font-mono text-[10px] tracking-[1.6px] uppercase text-muted">Not connected</span>
              <span className="text-[12.5px] font-medium text-ink">Sign in to begin</span>
            </div>
          </div>
        )}
      </div>
    </header>
  );
}

function timeAgo(ts: number): string {
  const delta = Math.max(0, Date.now() - ts);
  const min = Math.floor(delta / 60000);
  if (min < 1) return "just now";
  if (min < 60) return `${min}m ago`;
  const hr = Math.floor(min / 60);
  if (hr < 24) return `${hr}h ago`;
  return `${Math.floor(hr / 24)}d ago`;
}
