"use client";

import { Fragment, useState } from "react";
import { Sparkles, ArrowRight, GripVertical } from "lucide-react";
import { useStackshift } from "@/store";
import type { CreateContentTypeResponse, DetectedComponent, FieldType, MatchResult } from "@/types";

const TYPE_LABEL: Record<FieldType, string> = {
  single_line: "single-line", multi_line: "multi-line", rich_text: "rich-text",
  url: "link", file: "file", boolean: "boolean", number: "number", group: "group", reference: "ref",
};

const btnBase    = "inline-flex items-center gap-2 px-3.5 py-2 font-sans font-medium text-xs border cursor-pointer transition-all duration-[120ms] rounded-[3px] disabled:opacity-45 disabled:cursor-not-allowed disabled:pointer-events-none";
const btnDefault = `${btnBase} bg-ink text-paper border-line hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-accent`;
const btnGhost   = `${btnBase} bg-transparent text-ink border-line hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-card`;
const btnPrimary = "inline-flex items-center gap-2.5 px-[22px] py-[13px] bg-accent border border-accent text-paper font-sans font-medium text-sm cursor-pointer transition-all duration-[120ms] rounded-[3px] hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-accent-2 disabled:opacity-45 disabled:cursor-not-allowed disabled:pointer-events-none";

export default function MatchStep() {
  const components      = useStackshift((s) => s.components);
  const selectedIds     = useStackshift((s) => s.selectedIds);
  const matches         = useStackshift((s) => s.matches);
  const config          = useStackshift((s) => s.config);
  const setStep         = useStackshift((s) => s.setStep);
  const setMatchResolved = useStackshift((s) => s.setMatchResolved);
  const dryRun          = useStackshift((s) => s.dryRun);

  const [expanded, setExpanded]   = useState<string | null>(null);
  const [creatingId, setCreatingId] = useState<string | null>(null);
  const [err, setErr]             = useState<string | null>(null);

  const selectedComponents = components.filter((c) => selectedIds.includes(c.id));
  const allResolved        = matches.every((m) => m.status === "matched" || m.status === "partial");

  const handleCreate = async (c: DetectedComponent) => {
    setErr(null); setCreatingId(c.id);
    try {
      const res  = await fetch("/api/contentstack/create-content-type", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ config, component: c }) });
      const data = (await res.json()) as CreateContentTypeResponse;
      if (!data.ok || !data.contentType) { setErr(data.error ?? "Failed to create content type."); return; }
      setMatchResolved(c.id, data.contentType.uid, data.contentType.title);
    } catch (e) {
      setErr(e instanceof Error ? e.message : "Network error.");
    } finally { setCreatingId(null); }
  };

  return (
    <>
      <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
        <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">04 / MATCH</span>
        <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
          Map to Contentstack <em className="italic font-normal text-accent">types</em>.
        </h2>
      </div>
      <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
        For each component, we looked for a matching content type. Create the missing ones with one click — the schema is auto-inferred from the fields we detected.
      </p>

      {dryRun && (
        <div className="font-mono text-[11px] tracking-[1.5px] uppercase text-brand-yellow px-3.5 py-2.5 bg-brand-yellow/10 border border-brand-yellow/30 rounded-[3px] mb-4">
          Dry-run mode — content type creation is disabled. No changes will be written.
        </div>
      )}

      <table className="w-full border-collapse border border-line bg-card rounded-[3px] overflow-hidden">
        <thead>
          <tr>
            {["Detected Component", "Contentstack Content Type", "Status", "Action"].map((h, i) => (
              <th key={h} className="text-left px-[18px] py-3.5 font-mono text-[10px] uppercase tracking-[1.5px] text-muted border-b border-line bg-paper-2 font-medium" style={i === 3 ? { width: 220 } : {}}>
                {h}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {selectedComponents.map((c) => {
            const match = matches.find((m) => m.componentId === c.id);
            if (!match) return null;
            const open  = expanded === c.id;
            return (
              <Fragment key={c.id}>
                <tr className="hover:[&_td]:bg-paper">
                  <td className="px-[18px] py-[18px] border-b border-line/20 text-sm align-middle">
                    <div className="font-medium">{c.name}</div>
                    <div className="font-mono text-[10px] text-muted uppercase tracking-[1.5px] mt-1">{c.suggestedUid}</div>
                  </td>
                  <td className="px-[18px] py-[18px] border-b border-line/20 text-sm align-middle">
                    <span className="text-muted font-mono text-lg mr-3">→</span>
                    {match.contentTypeTitle ?? <span className="text-muted">—</span>}
                  </td>
                  <td className="px-[18px] py-[18px] border-b border-line/20 text-sm align-middle">
                    <MatchBadge status={match.status} />
                  </td>
                  <td className="px-[18px] py-[18px] border-b border-line/20 text-sm align-middle">
                    {match.status === "missing" || match.status === "partial" ? (
                      <button
                        className={btnDefault}
                        onClick={() => handleCreate(c)}
                        disabled={creatingId === c.id || dryRun}
                        title={dryRun ? "Disabled in dry-run mode" : undefined}
                      >
                        {creatingId === c.id
                          ? <><span className="inline-block w-3 h-3 rounded-full border-2 border-paper-2 border-t-accent animate-spin" /> Creating…</>
                          : <><Sparkles size={12} /> Create type</>}
                      </button>
                    ) : (
                      <span className="font-mono text-[11px] text-muted tracking-[1px] uppercase">reusing</span>
                    )}
                    <button className={`${btnGhost} ml-2`} onClick={() => setExpanded(open ? null : c.id)}>
                      {open ? "Hide schema" : "View schema"}
                    </button>
                  </td>
                </tr>
                {open && (
                  <tr>
                    <td colSpan={4} className="p-0">
                      <SchemaPreview component={c} match={match} />
                    </td>
                  </tr>
                )}
              </Fragment>
            );
          })}
        </tbody>
      </table>

      {err && <p className="mt-4 text-accent text-sm">{err}</p>}

      <div className="mt-7 flex gap-3 items-center">
        <button className={btnPrimary} onClick={() => setStep("page")} disabled={!allResolved}>
          Continue to page setup <ArrowRight size={12} />
        </button>
        {!allResolved && (
          <span className="font-mono text-[11px] tracking-[1.5px] uppercase text-muted">Resolve all types to continue</span>
        )}
      </div>
    </>
  );
}

function MatchBadge({ status }: { status: "matched" | "partial" | "missing" }) {
  const cls = {
    matched: "bg-brand-green text-paper border-brand-green",
    partial:  "bg-brand-yellow text-ink border-brand-yellow",
    missing:  "bg-paper text-accent border-accent",
  }[status];
  return (
    <span className={`font-mono text-[10px] font-semibold px-2.5 py-[5px] border uppercase tracking-[1.2px] inline-flex items-center rounded-[2px] ${cls}`}>
      {status}
    </span>
  );
}

function SchemaPreview({ component, match }: { component: DetectedComponent; match: MatchResult }) {
  return (
    <div className="bg-paper border-t border-line p-7">
      <div className="flex justify-between items-baseline mb-5 pb-4 border-b border-dashed border-line">
        <h3 className="font-serif font-medium text-2xl tracking-[-0.5px]">{component.name} — inferred schema</h3>
        <span className="font-mono text-[11px] text-accent uppercase tracking-[2px]">
          {match.contentTypeUid ?? component.suggestedUid}
        </span>
      </div>
      {component.fields.map((f) => (
        <div key={f.uid} className="grid items-center gap-3.5 py-3 border-b border-dotted border-paper-2 text-sm" style={{ gridTemplateColumns: "24px 1fr 180px 100px 80px" }}>
          <span className="text-muted cursor-grab"><GripVertical size={14} /></span>
          <div>
            <div className="font-medium">{f.displayName}</div>
            <div className="font-mono text-xs text-muted">{f.uid}</div>
          </div>
          <span className="font-mono text-xs text-muted">{f.source ?? "auto"}</span>
          <span className={`font-mono text-[10px] px-2 py-[3px] uppercase tracking-[1px] rounded-[2px] justify-self-start ${f.type === "group" ? "bg-accent text-paper" : f.type === "rich_text" ? "bg-brand-green text-paper" : "bg-ink text-paper"}`}>
            {TYPE_LABEL[f.type]}
          </span>
          <span className={`font-mono text-[10px] uppercase tracking-[1px] ${f.required ? "text-accent" : "text-muted"}`}>
            {f.required ? "required" : "optional"}
          </span>
        </div>
      ))}
    </div>
  );
}
