"use client";

import { useMemo, useState } from "react";
import { Code2, Upload, X } from "lucide-react";
import { useStackshift } from "@/store";
import { entryTitle } from "@/lib/entry-title";
import type { DetectedField, MigrateResponse } from "@/types";

const inputCls    = "w-full px-3 py-2.5 border border-line bg-paper font-sans text-sm outline-none rounded-[3px] transition-all duration-150 focus:border-accent focus:bg-card focus:shadow-focus";
const textareaCls = "w-full px-3 py-2.5 border border-line bg-paper font-serif text-[15px] leading-[1.5] outline-none rounded-[3px] resize-y min-h-[80px] transition-all duration-150 focus:border-accent focus:bg-card focus:shadow-focus";
const labelCls    = "font-mono text-[10px] uppercase tracking-[1.5px] text-muted block mb-1.5";
const btnPrimary  = "inline-flex items-center gap-2.5 px-7 py-4 bg-accent border border-accent text-paper font-sans font-medium text-[15px] cursor-pointer transition-all duration-[120ms] rounded-[3px] hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-accent-2 disabled:opacity-45 disabled:cursor-not-allowed disabled:pointer-events-none";
const btnGhost    = "inline-flex items-center gap-2 px-3.5 py-2 bg-transparent text-ink font-sans font-medium text-xs border border-line cursor-pointer transition-all duration-[120ms] rounded-[3px] hover:-translate-x-0.5 hover:-translate-y-0.5 hover:shadow-btn-ink hover:bg-card";

export default function PreviewStep() {
  const components           = useStackshift((s) => s.components);
  const selectedIds          = useStackshift((s) => s.selectedIds);
  const matches              = useStackshift((s) => s.matches);
  const config               = useStackshift((s) => s.config);
  const dryRun               = useStackshift((s) => s.dryRun);
  const uploadAssets         = useStackshift((s) => s.uploadAssets);
  const activeId             = useStackshift((s) => s.activeComponentId);
  const selectedPageTypeUid  = useStackshift((s) => s.selectedPageTypeUid);
  const pageComponentIds     = useStackshift((s) => s.pageComponentIds);
  const pageEntryUrl         = useStackshift((s) => s.pageEntryUrl);
  const pageEntryTitle       = useStackshift((s) => s.pageEntryTitle);
  const setActive            = useStackshift((s) => s.setActiveComponent);
  const updateField          = useStackshift((s) => s.updateComponentField);
  const updateName           = useStackshift((s) => s.updateComponentName);
  const setMigrationResult   = useStackshift((s) => s.setMigrationResult);
  const setStep              = useStackshift((s) => s.setStep);

  const [pushing, setPushing] = useState(false);
  const [err, setErr]         = useState<string | null>(null);
  const [jsonOpen, setJsonOpen] = useState(false);

  const selectedComponents = useMemo(() => components.filter((c) => selectedIds.includes(c.id)), [components, selectedIds]);
  const active = selectedComponents.find((c) => c.id === activeId) ?? selectedComponents[0];

  const previewPayload = useMemo(() => {
    const payload = selectedComponents.reduce<Record<string, unknown>>((acc, c) => {
      const ctUid = matches.find((m) => m.componentId === c.id)?.contentTypeUid ?? c.suggestedUid;
      const entry: Record<string, unknown> = { title: entryTitle(c.name) };
      c.fields.forEach((f) => { if (f.uid !== "title") entry[f.uid] = f.value; });
      acc[ctUid] = entry;
      return acc;
    }, {});

    // Include the page entry preview when a page type is configured.
    if (selectedPageTypeUid) {
      const modularBlocks = pageComponentIds.map((cid) => {
        const c     = selectedComponents.find((x) => x.id === cid);
        const ctUid = matches.find((m) => m.componentId === cid)?.contentTypeUid
          ?? c?.suggestedUid ?? cid;
        return {
          [`${ctUid}_block`]: {
            [`${ctUid}_ref`]: [
              {
                _content_type_uid: ctUid,
                uid: "<entry-uid-assigned-at-migration>",
              },
            ],
          },
        };
      });
      payload[`${selectedPageTypeUid}__page_entry`] = {
        title:          entryTitle(pageEntryTitle || "Page"),
        url:            pageEntryUrl,
        modular_blocks: modularBlocks,
      };
    }

    return payload;
  }, [selectedComponents, matches, selectedPageTypeUid, pageComponentIds, pageEntryUrl, pageEntryTitle]);

  const handlePush = async () => {
    setErr(null); setPushing(true);
    try {
      const body = {
        config,
        components:      selectedComponents,
        matches,
        dryRun,
        uploadAssets,
        // Page entry data from the Page step
        pageTypeUid:     selectedPageTypeUid ?? null,
        pageComponentIds,
        pageEntryUrl,
        pageEntryTitle,
      };
      const res  = await fetch("/api/contentstack/migrate", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
      const data = (await res.json()) as MigrateResponse;
      setMigrationResult(data.result);
      setStep("done");
    } catch (e) {
      setErr(e instanceof Error ? e.message : "Push failed.");
    } finally { setPushing(false); }
  };

  return (
    <>
      <div className="flex items-baseline gap-6 mb-2.5 flex-wrap">
        <span className="font-mono text-[11px] tracking-[2.2px] text-accent uppercase">05 / PREVIEW</span>
        <h2 className="font-serif font-medium text-[42px] tracking-[-1.2px] leading-[1.02]">
          Review &amp; <em className="italic font-normal text-accent">tweak</em>.
        </h2>
      </div>
      <p className="text-muted text-[15.5px] mb-9 max-w-[640px] leading-[1.6]">
        Everything below will become entries in Contentstack. Edit inline, then push. Toggle dry-run on the URL step if you want to inspect the payload without writing anything.
      </p>

      <div className="grid border border-line bg-card rounded-[3px] overflow-hidden" style={{ gridTemplateColumns: "260px 1fr" }}>
        {/* sidebar */}
        <aside className="bg-paper-2 border-r border-line p-5">
          <h4 className="font-mono text-[10px] uppercase tracking-[2px] text-muted mb-3.5">
            Components ({selectedComponents.length})
          </h4>
          {selectedComponents.map((c, i) => (
            <div
              key={c.id}
              className={`px-3.5 py-3 border border-line mb-2 cursor-pointer flex items-center justify-between text-sm font-medium rounded-[3px] transition-all duration-[120ms] hover:translate-x-0.5 ${active?.id === c.id ? "bg-ink text-paper border-ink" : "bg-card text-ink"}`}
              onClick={() => setActive(c.id)}
            >
              <span>{c.name}</span>
              <span className={`font-mono text-[10px] opacity-60`}>{String(i + 1).padStart(2, "0")}</span>
            </div>
          ))}
        </aside>

        {/* main editor */}
        <main className="p-7">
          {active ? (
            <>
              <div className="font-mono text-[10px] uppercase text-muted tracking-[1.5px] mb-5">
                {matches.find((m) => m.componentId === active.id)?.contentTypeUid ?? active.suggestedUid}
              </div>

              {/* editable entry title */}
              <div className="mb-5">
                <label className={labelCls}>Entry title</label>
                <input className={inputCls} value={active.name} onChange={(e) => updateName(active.id, e.target.value)} placeholder="Entry title" />
                <span className="font-mono block mt-1.5 text-[11px] text-muted tracking-[0.5px]">
                  sent as: <strong className="text-ink">{entryTitle(active.name)}</strong>
                </span>
              </div>

              <div className="mt-5">
                {active.fields.map((f) => (
                  <FieldEditor key={f.uid} field={f} onChange={(value) => updateField(active.id, f.uid, value)} />
                ))}
              </div>
            </>
          ) : (
            <p className="text-muted">Select a component to edit.</p>
          )}
        </main>
      </div>

      <div className="mt-7 flex gap-3 items-center flex-wrap">
        <button className={btnGhost} onClick={() => setJsonOpen(true)}>
          <Code2 size={14} /> View JSON payload
        </button>
        <button className={btnPrimary} onClick={handlePush} disabled={pushing}>
          {pushing
            ? <><span className="inline-block w-3.5 h-3.5 rounded-full border-2 border-paper-2 border-t-accent animate-spin" /> Pushing…</>
            : <><Upload size={14} /> {dryRun ? "Run dry-run →" : "Push to Contentstack →"}</>}
        </button>
        {err && <span className="text-accent text-sm">{err}</span>}
      </div>

      {/* JSON modal */}
      {jsonOpen && (
        <div className="fixed inset-0 bg-ink/60 flex items-center justify-center z-50 p-8" onClick={() => setJsonOpen(false)}>
          <div className="bg-card border border-line shadow-hard rounded-[3px] w-full max-w-[820px] max-h-[80vh] flex flex-col" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center gap-2.5 px-4 py-[11px] bg-paper-2 border-b border-line font-mono text-[11px] text-muted">
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#ff5f57]" />
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#febc2e]" />
              <span className="w-2.5 h-2.5 rounded-full border border-line bg-[#28c840]" />
              <span className="flex-1 bg-card border border-line px-2.5 py-[5px] rounded-[2px] ml-3">payload.json</span>
              <button className="ml-2 bg-transparent border-none cursor-pointer text-muted hover:text-ink" onClick={() => setJsonOpen(false)} aria-label="Close">
                <X size={14} />
              </button>
            </div>
            <pre className="flex-1 overflow-auto p-5 text-xs font-mono leading-[1.7] bg-ink text-[#a8e6a3] m-0">
              {JSON.stringify(previewPayload, null, 2)}
            </pre>
          </div>
        </div>
      )}
    </>
  );
}

function FieldEditor({ field, onChange }: { field: DetectedField; onChange: (v: unknown) => void }) {
  const lbl = <label className={labelCls}>{field.displayName}</label>;
  switch (field.type) {
    case "single_line":
      return <div className="mb-5">{lbl}<input className={inputCls} value={(field.value as string) ?? ""} onChange={(e) => onChange(e.target.value)} /></div>;
    case "multi_line":
    case "rich_text":
      return (
        <div className="mb-5">{lbl}
          <textarea className={textareaCls} value={typeof field.value === "string" ? field.value : JSON.stringify(field.value)} onChange={(e) => onChange(e.target.value)} />
        </div>
      );
    case "url": {
      const v = (field.value as { title?: string; href?: string }) ?? {};
      return (
        <div className="mb-5">{lbl}
          <input className={inputCls} value={v.title ?? ""} placeholder="Title" onChange={(e) => onChange({ ...v, title: e.target.value })} />
          <input className={`${inputCls} mt-1.5`} value={v.href ?? ""} placeholder="https://…" onChange={(e) => onChange({ ...v, href: e.target.value })} />
        </div>
      );
    }
    case "file":
      return <div className="mb-5"><label className={labelCls}>{field.displayName} — (asset URL)</label><input className={inputCls} value={(field.value as string) ?? ""} onChange={(e) => onChange(e.target.value)} /></div>;
    case "group":
      return (
        <div className="mb-5">{lbl}
          <label className={labelCls}>{field.displayName} — {(field.value as unknown[])?.length ?? 0} items</label>
          <textarea
            className={`${textareaCls} font-mono text-xs`}
            value={JSON.stringify(field.value, null, 2)}
            onChange={(e) => { try { onChange(JSON.parse(e.target.value)); } catch { /* ignore while typing */ } }}
          />
        </div>
      );
    default:
      return <div className="mb-5">{lbl}<input className={inputCls} value={String(field.value ?? "")} onChange={(e) => onChange(e.target.value)} /></div>;
  }
}
